#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdlib>

int main() {
    std::string user_code_filename = "3909.cpp";

    std::vector<std::pair<std::string, std::string>> test_cases = {
        {
            "1\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Monday\n"
        },
        {
            "7\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Sunday\n"
        },
        {
            "0\n2\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Invalid input. The number must be between 1 and 7.\nEnter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Tuesday\n"
        },
        {
            "8\n6\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Invalid input. The number must be between 1 and 7.\nEnter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Saturday\n"
        },
        {
            "abc\n3\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Invalid input. Please enter a numerical value.\nEnter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Wednesday\n"
        },
        {
            "hello world\n5\n",
            "Enter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Invalid input. Please enter a numerical value.\nEnter an integer between 1 and 7 (1 for Monday, 7 for Sunday): Friday\n"
        }
    };

    std::string compile_cmd = "g++ -o user_program " + user_code_filename;
    if (system(compile_cmd.c_str()) != 0) {
        std::cerr << "Compilation failed for " << user_code_filename << std::endl;
        return 1;
    }

    int passed_tests = 0;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input = test_cases[i].first;
        std::string expected_output = test_cases[i].second;

        std::ofstream input_file("temp_input.txt");
        if (!input_file.is_open()) {
            std::cerr << "Error: Could not open temp_input.txt\n";
            return 1;
        }
        input_file << input;
        input_file.close();

        std::string run_cmd = "./user_program < temp_input.txt > temp_output.txt";
        system(run_cmd.c_str());

        std::ifstream output_file("temp_output.txt");
        if (!output_file.is_open()) {
            std::cerr << "Error: Could not open temp_output.txt\n";
            return 1;
        }
        std::stringstream ss;
        ss << output_file.rdbuf();
        std::string actual_output = ss.str();
        output_file.close();

        if (actual_output == expected_output) {
            passed_tests++;
        }
    }

    system("rm -f temp_input.txt temp_output.txt user_program");

    return (passed_tests == test_cases.size() ? 0 : 1);
}
